public class CustomBiomeSource extends BiomeSource {
    private final Registry<Biome> biomeRegistry;
    private final Map<Biome, Climate.ParameterPoint> biomeParameters = new HashMap<>();

    public CustomBiomeSource(Registry<Biome> biomeRegistry) {
        this.biomeRegistry = biomeRegistry;
    }

    @Override
    public Biome getBiome(int x, int y, int z, Climate.Sampler sampler) {
        // TODO: 根据位置返回生物群系
        return biomeRegistry.get(ModBiomes.CUSTOM_BIOME_KEY);
    }

