public static final Codec<CustomChunkGenerator> CODEC = RecordCodecBuilder.create(instance ->
    instance.group(
        BiomeSource.CODEC.fieldOf("biome_source").forGetter(CustomChunkGenerator::getBiomeSource)
    ).apply(instance, CustomChunkGenerator::new));

Registry.register(Registries.CHUNK_GENERATOR, new Identifier("modid", "custom"), CODEC);

public class FlatWorldChunkGenerator extends ChunkGenerator {
    private final List<BlockState> layers;

    public FlatWorldChunkGenerator(BiomeSource biomeSource, List<BlockState> layers) {
        super(biomeSource);
        this.layers = layers;
    }

    @Override
    public void buildSurface(ChunkRegion region, StructureAccessor structures, NoiseConfig noiseConfig, Chunk chunk) {
        BlockPos.Mutable pos = new BlockPos.Mutable();
        for (int x = 0; x < 16; x++) {
            for (int z = 0; z < 16; z++) {
                for (int i = 0; i < layers.size(); i++) {
                    pos.set(chunk.getPos().getStartX() + x, i, chunk.getPos().getStartZ() + z);
                    chunk.setBlockState(pos, layers.get(i), false);
                }
            }
        }
    }
}

